// Parse Facebook ref param for ad attribution
const body = $input.item.json;
const messaging = body?.entry?.[0]?.messaging?.[0];
const psid = messaging?.sender?.id;
const ref = messaging?.referral?.ref || '';

// ref format: 'camp_{campaign_id}_set_{adset_id}_ad_{ad_id}'
const parsed = {};
if (ref) {
  parsed.campaign_id = ref.match(/camp_([^_]+)/)?.[1];
  parsed.adset_id    = ref.match(/set_([^_]+)/)?.[1];
  parsed.ad_id       = ref.match(/ad_([^_]+)/)?.[1];
}

return [{ json: { psid, ref, ...parsed, raw: messaging } }];
